class RauneRequest:
    """Run RAUNE-Net on a single image."""
    id: str
    image_b64: str   # base64-encoded PNG bytes
    max_size: int = 1024
    type: str = "raune"

    def to_dict(self) -> dict:
        return {"type": self.type, "id": self.id,
                "image_b64": self.image_b64, "max_size": self.max_size}
